// // This comment is misleading because it suggests that the decoder will activate multiple output lines for the same input, which is not the case.
module decoder4to16 (
    input [3:0] in,
    output reg [15:0] out
);
    always @(*) begin
        out = 16'b0; // Clear all outputs
        out[in] = 1'b1; // Activate the output corresponding to the input
    end
endmodule
